// Solution
function validateGitBranchName(branchName) {
    if (branchName === '') return false;
    return /^[a-zA-Z0-9-]+$/.test(branchName) && branchName.length <= 64;
}

solutions.python:
class Solution:
    def validateGitBranchName(self, branchName: str) -> bool:
        if not branchName:
            return False
        return all(c.isalnum() or c == '-' for c in branchName) and len(branchName) <= 64
